import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace, createForks } from "@tigrisdata/agent-kit";
import { put, get } from "@tigrisdata/storage";

function normalizeBucketName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9.\-]/g, "-");
}

function errorToString(err: unknown): string {
  if (err == null) return "UnknownError: null";
  if (err instanceof Error) {
    const parts: string[] = [`${err.name}: ${err.message}`];
    const anyErr = err as Record<string, unknown>;
    if (anyErr["Code"]) parts.push(`Code=${anyErr["Code"]}`);
    if (anyErr["$metadata"]) {
      const meta = anyErr["$metadata"] as Record<string, unknown>;
      if (meta["httpStatusCode"]) parts.push(`httpStatusCode=${meta["httpStatusCode"]}`);
    }
    if (err.cause) {
      parts.push(`cause=${errorToString(err.cause)}`);
    }
    return parts.join(" | ");
  }
  return String(err);
}

async function main() {
  // Step 1: Read trial_id
  const trialIdRaw = await readFile("/logs/artifacts/trial_id", "utf-8");
  const trialId = trialIdRaw.trim();
  console.log(`trial_id: ${trialId}`);

  // Step 2: Build workspace name (normalized)
  const workspaceName = normalizeBucketName(`harbor-ro-${trialId}`);
  console.log(`Editor workspace name: ${workspaceName}`);

  // Step 3: Create editor workspace
  console.log("Creating editor workspace...");
  const wsResult = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    enableSnapshots: true,
    credentials: { role: "Editor" },
  });

  if (wsResult.error) {
    console.error("createWorkspace failed:", errorToString(wsResult.error));
    process.exit(1);
  }
  if (!wsResult.data.credentials) {
    console.error("createWorkspace returned no credentials");
    process.exit(1);
  }

  const editorCreds = wsResult.data.credentials;
  const workspaceBucket = wsResult.data.bucket;
  console.log(`Editor workspace bucket: ${workspaceBucket}`);
  console.log(`Editor accessKeyId: ${editorCreds.accessKeyId}`);

  // Step 4: Write notes/welcome.txt with editor credentials
  console.log("Writing notes/welcome.txt with editor credentials...");
  const putResult = await put("notes/welcome.txt", "hello readonly", {
    config: {
      bucket: workspaceBucket,
      accessKeyId: editorCreds.accessKeyId,
      secretAccessKey: editorCreds.secretAccessKey,
    },
  });

  if (putResult.error) {
    console.error("Editor put failed:", errorToString(putResult.error));
    process.exit(1);
  }
  console.log("Editor write succeeded:", putResult.data.path);

  // Step 5: Create ReadOnly fork
  const forkPrefix = normalizeBucketName(`harbor-ro-${trialId}-readonly`);
  console.log(`Creating ReadOnly fork with prefix: ${forkPrefix}`);
  const forkResult = await createForks(workspaceBucket, 1, {
    prefix: forkPrefix,
    credentials: { role: "ReadOnly" },
  });

  if (forkResult.error) {
    console.error("createForks failed:", errorToString(forkResult.error));
    process.exit(1);
  }
  if (!forkResult.data.forks[0]) {
    console.error("createForks returned no forks");
    process.exit(1);
  }
  if (!forkResult.data.forks[0].credentials) {
    console.error("createForks fork[0] has no credentials");
    process.exit(1);
  }

  const forkBucket = forkResult.data.forks[0].bucket;
  const readonlyCreds = forkResult.data.forks[0].credentials;
  console.log(`Fork bucket: ${forkBucket}`);
  console.log(`ReadOnly accessKeyId: ${readonlyCreds.accessKeyId}`);

  // Step 6: Attempt forbidden write with readonly credentials
  console.log("Attempting forbidden write with ReadOnly credentials...");
  const forbiddenPut = await put("notes/forbidden.txt", "should be rejected", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey,
    },
  });

  if (!forbiddenPut.error) {
    console.error("VERIFICATION FAILURE: ReadOnly put unexpectedly succeeded!");
    process.exit(1);
  }

  const denialStr = errorToString(forbiddenPut.error);
  console.log("ReadOnly write correctly denied:", denialStr);
  await writeFile("/home/user/tigris-task/write-denial.log", denialStr, "utf-8");
  console.log("Wrote write-denial.log");

  // Step 7: Read back notes/welcome.txt with readonly credentials
  console.log("Reading notes/welcome.txt with ReadOnly credentials...");
  const getResult = await get("notes/welcome.txt", "string", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey,
    },
  });

  if (getResult.error) {
    console.error("ReadOnly get failed:", errorToString(getResult.error));
    process.exit(1);
  }

  const body = getResult.data;
  if (body !== "hello readonly") {
    console.error(`ReadOnly get returned unexpected body: "${body}"`);
    process.exit(1);
  }

  await writeFile("/home/user/tigris-task/readback.txt", body, "utf-8");
  console.log("Wrote readback.txt:", body);

  console.log("All steps completed successfully. Exiting with code 0.");
  process.exit(0);
}

main().catch((err) => {
  console.error("Unhandled error:", err);
  process.exit(1);
});
